def range_summary(nums):
    runs = []
    current_start, current_end = None, None
    for num in sorted(set(nums)):
        if current_start is None:
            current_start = num
        elif num == current_end + 1:
            current_end = num
        else:
            runs.append(f'{current_start}-{current_end}' if current_start != current_end else current_start)
            current_start = num
    runs.append(current_start if current_start != current_end else current_end)
    return ', '.join(runs)
